package com.adm.url_parser.impls.main_sites.instaimport android.util.Logimport com.adm.url_parser.commons.impl.get_in_device_api.GetInDeviceApiImplimport com.adm.url_parser.impls.main_sites.insta.impl.InstagramDirectUrlApiimport com.adm.url_parser.impls.main_sites.insta.impl.InstagramDirectUrlApiVideoPreviewimport com.adm.url_parser.impls.main_sites.insta.impl.InstagramDownloaderUsingCookiesimport com.adm.url_parser.impls.main_sites.insta.impl.graphql.GraphQlConfigsimport com.adm.url_parser.impls.main_sites.insta.impl.graphql.InstaGraphQlScrapperimport com.adm.url_parser.interfaces.ApiLinkScrapperimport com.adm.url_parser.models.ParsedVideoimport kotlinx.coroutines.CompletableDeferredimport kotlinx.coroutines.Dispatchersimport kotlinx.coroutines.asyncimport kotlinx.coroutines.awaitAllimport kotlinx.coroutines.selects.selectimport kotlinx.coroutines.supervisorScopeclass InstaDownloaderMain(    private val graphQlConfigs: GraphQlConfigs,) : ApiLinkScrapper {    companion object {        private const val TAG = "InstaDownloaderMain"    }    override suspend fun scrapeLink(url: String): Result<ParsedVideo?> = supervisorScope {        val cookieDeferred = async(Dispatchers.IO) {            runCatching { InstagramDownloaderUsingCookies().scrapeLink(url) }                .getOrNull()        }        val fallbackWinner = CompletableDeferred<Result<ParsedVideo?>>()        val fallbackTasks: List<suspend () -> Result<ParsedVideo?>> =            if (url.contains("/p/")) {                listOf { InstaGraphQlScrapper(graphQlConfigs).scrapeLink(url) }            } else {                listOf(                    { InstagramDirectUrlApiVideoPreview().scrapeLink(url) },                    { InstagramDirectUrlApi().scrapeLink(url) },                    { InstaGraphQlScrapper(graphQlConfigs).scrapeLink(url) },                    { GetInDeviceApiImpl().scrapeLink(url) }                )            }        val fallbackJobs = fallbackTasks.mapIndexed { index, task ->            async(Dispatchers.IO) {                try {                    val result = task()                    val video = result.getOrNull()                    if (result.isSuccess && video.isValid()) {                        Log.d(TAG, "Winner: scraper[$index]")                        fallbackWinner.complete(result) // store first valid                    } else {                        Log.d(TAG, "Invalid result from scraper[$index]")                    }                } catch (e: Exception) {                    Log.e(TAG, "Scraper[$index] failed: ${e.message}")                }            }        }        // Wait for cookies (decision authority)        val cookieResult = cookieDeferred.await()        val cookieModel = cookieResult?.getOrNull()        val finalResult =            if (cookieResult?.isSuccess == true && cookieModel.isValid()) {                Log.d(TAG, "Winner->InstagramDownloaderUsingCookies (priority) :$cookieModel")                cookieResult            } else {                // Cookies failed → now fallback can win                select<Result<ParsedVideo?>?> {                    fallbackWinner.onAwait { it }                    async { fallbackJobs.awaitAll() }.onAwait { null }                }            }        fallbackJobs.forEach { it.cancel() }        finalResult ?: Result.failure(Exception("No valid media found"))    }    private fun ParsedVideo?.isValid(): Boolean {        if (this == null) return false        if (qualities.isEmpty()) return false        return !qualities.firstOrNull()?.url.isNullOrBlank()    }}